      "content": "// src/modules/tasks/service.js
const { randomUUID } = require('node:crypto');
const tasksStore = [];

const createTask = (name) => {
  const task = {
    id: randomUUID(),
    name,
    status: 'todo',
  };
  tasksStore.push(task);
  return task;
};

const getTasks = (status) => {
  if (!status) {
    return tasksStore;
  }
  return tasksStore.filter(task => task.status === status);
};

const updateTask = async (taskId, newStatus) => {
  const taskIndex = tasksStore.findIndex(task => task.id === taskId);
  if (taskIndex === -1) {
    throw { code: 'NOT_FOUND', message: 'Task not found' };
  }
  tasksStore[taskIndex].status = newStatus;
  return tasksStore[taskIndex];
};

const getTaskById = (taskId) => {
  return tasksStore.find(task => task.id === taskId);
};

module.exports = {
  createTask,
  getTasks,
  updateTask,
  getTaskById,
};
